parameters.query:
SELECT DNS.DA, DNS.Article, DNS.DésignationArticle, DNS.QteDA, DNS.STU_0 AS Unite, '' as Marque  FROM x3.BASE1.Y_DA_NON_SOLDEES DNS
WHERE DNS.Famille NOT LIKE 'SERVICE%' AND DNS.Famille NOT LIKE 'LOGISTIQUE%' AND DNS.Famille NOT LIKE 'R.H'
AND DNS.Article NOT IN ('A09985', 'A10107', 'A10136');

