// Récupération des données brutes provenant du nœud précédent
const items = $input.all();

// Objet pour regrouper par Fournisseur
const grouped = {};

for (const item of items) {
  const data = item.json;
  const fournisseur = data.Fournisseur;

  if (!grouped[fournisseur]) {
    grouped[fournisseur] = {
      ...data,
      Articles: []
    };
  }

  // Ajouter l’article dans la liste
  grouped[fournisseur].Articles.push({
    Article: data.Article,
    Description: data.DescriptionFinale,
    QTY: data.QTY,
    UNITE: data.UNITE,
    MARQ: data.MARQ,
    DA: data.DA
  });
}

// Convertir en tableau d'items n8n
return Object.values(grouped).map(f => ({ json: f }));

// Dans un nœud Code (JavaScript)
const items = $input.all();

// Créer un objet pour regrouper par fournisseur et article
const groupedData = {};

items.forEach(item => {
  const fournisseurId = item.json.Fournisseur;
  const fournisseurNom = item.json["NOM FOURNISSEUR"];
  const telephone = item.json.TELE;
  const email = item.json.EMAIL;
  const fax = item.json.FAX;

  // Initialiser le fournisseur s'il n'existe pas
  if (!groupedData[fournisseurId]) {
    groupedData[fournisseurId] = {
      "TELE": telephone,
      "EMAIL": email,
      "FAX": fax,
      "Fournisseur": fournisseurId,
      "NOM FOURNISSEUR": fournisseurNom,
      "Articles": {}
    };
  }

  // Parcourir tous les articles
  item.json.Articles.forEach(article => {
    const articleId = article.Article;
    const description = article.Description;
    const quantite = parseInt(article.QTY) || 0;
    const unite = article.UNITE;
    const marque = article.MARQ;
    const da = article.DA;

    // Initialiser l'article s'il n'existe pas
    if (!groupedData[fournisseurId].Articles[articleId]) {
      groupedData[fournisseurId].Articles[articleId] = {
        "Article": articleId,
        "Description": description,
        "QTY_TOTAL": 0,
        "Unite": unite,
        "Marque": marque,
        "DAs": []
      };
    }

    // Ajouter la quantité
    groupedData[fournisseurId].Articles[articleId].QTY_TOTAL += quantite;

    // Ajouter le DA s'il n'est pas déjà présent
    if (!groupedData[fournisseurId].Articles[articleId].DAs.includes(da)) {
      groupedData[fournisseurId].Articles[articleId].DAs.push(da);
    }
  });
});

// Convertir en format de sortie
const output = [];

Object.keys(groupedData).forEach(fournisseurId => {
  const fournisseur = groupedData[fournisseurId];

  // Convertir les articles en tableau
  const articlesArray = Object.values(fournisseur.Articles);

  output.push({
    json: {
      "TELE": fournisseur.TELE,
      "EMAIL": fournisseur.EMAIL,
      "FAX": fournisseur.FAX,
      "Fournisseur": fournisseur.Fournisseur,
      "NOM FOURNISSEUR": fournisseur["NOM FOURNISSEUR"],
      "Articles": articlesArray
    }
  });
});

return output;

const items = $input.all();
const results = [];

items.forEach(fournisseurData => {
  const fournisseur = fournisseurData.json;

  // Générer les lignes de la table
  let tableRows = '';
  let totalGeneral = 0;

  fournisseur.Articles.forEach((article, index) => {
    totalGeneral += article.QTY_TOTAL;

    tableRows += `
      <tr style="${index % 2 === 0 ? 'background-color: #f9f9f9;' : ''}">
        <td style="padding: 10px; border-bottom: 1px solid #eee; font-size: 13px; color: #333333;">
          <strong>${article.Article}</strong>
        </td>
        <td style="padding: 10px; border-bottom: 1px solid #eee; font-size: 13px; color: #555555;">
          ${article.Description}
        </td>
        <td style="padding: 10px; border-bottom: 1px solid #eee; font-size: 13px; color: #555555; text-align: center;">
            ${article.Marque}
          </td>
        <td style="padding: 10px; border-bottom: 1px solid #eee; text-align: center; font-size: 13px; color: #333333; font-weight: 600;">
          ${article.QTY_TOTAL} ${article.Unite}
        </td>
        <td style="padding: 10px; border-bottom: 1px solid #eee; font-size: 13px; color: #555555;">
          ${article.DAs.join(', ')}
        </td>
      </tr>
    `;
  });

  // Ajouter le total
  tableRows += `
    <tr style="background-color: #f0f7ff;">
      <td colspan="4" style="padding: 12px 10px; font-size: 13px; color: #333333; border-top: 2px solid #667eea;">
        <strong>Total général : <strong>Articles différents : ${fournisseur.Articles.length}</strong>
      </td>
    </tr>
  `;

  // Ajouter les liens pour chaque article (optionnel)
  let articleLinks = '';
  fournisseur.Articles.forEach(article => {
    articleLinks += `
      <tr>
        <td style="padding:5px 0; font-size:13px; color:#555555;">
          • <a href="https://www.jbel-annour.ma/agent-achat/form-achat.php?artref=${article.Article}&frsref=${fournisseur.Fournisseur}&qty=${article.QTY_TOTAL}&intitul=${encodeURIComponent(article.Description)}" 
             style="color:#667eea; text-decoration:none;">
            ${article.Article} - ${article.Description} (Qté: ${article.QTY_TOTAL})
          </a>
        </td>
      </tr>
    `;
  });

  results.push({
    json: {
      ...fournisseur,
      tableRows: tableRows,
      totalGeneral: totalGeneral,
      articleLinks: articleLinks,
      emailSubject: `Commande regroupée - ${fournisseur["NOM FOURNISSEUR"]} - ${new Date().toLocaleDateString('fr-FR')}`,
      recipientEmail: fournisseur.EMAIL,
      recipientName: fournisseur["NOM FOURNISSEUR"]
    }
  });
});

return results;
